sys_script.script:
/**
 * Created date   : 14/05/2026
 * Author         : Quynhttn
 * Type           : Before Business Rule
 * Description    : Calculate duration of ticket based on formula
 *                  Close Date - Ticker Date
 */
(function executeRule(current, previous /*null when async*/) {
	// Get Recruitment Request record and calculate ticket duration
	var recruitmentRequestId = current.getValue('u_bid_recruit_id');
	var grRecuitmentRequest = new GlideRecord('x_1763182_talent_0_recruitment_request');

	if(grRecuitmentRequest.get(recruitmentRequestId)) {
		// Calculate duration between Ticket Date and Close Date
		var ticketDateGDT = GlideDateTime(grRecuitmentRequest.getValue('u_start_date'));
		var closeDateGDT = GlideDateTime(current.getValue('u_closed_date'));
		var durationOfTicket = GlideDateTime.subtract(ticketDateGDT, closeDateGDT);
		var durationOfTicketInDays = Math.floor(durationOfTicket.getNumericValue() / 86400000);

		// Update Duration of Ticket field
		current.setValue('u_duration_of_ticket', durationOfTicketInDays);
		current.update();
	}

})(current, previous);
